Hey

It should be called in the command (the model should stay agnostic to the UI).

You can extract the `showDialog` call from `FileList` to its own file (in the `widgets` folder as this is not a react component). The refactored code could look like:

```ts
  async function discardAllChanges(model: IGitExtension, trans: TranslationBundle): Promise<void> {

    const result = await showDialog({
      title: trans.__('Discard all changes'),
      body: trans.__(
        'Are you sure you want to permanently discard changes to all files? This action cannot be undone.'
      ),
      buttons: [
        Dialog.cancelButton({ label: trans.__('Cancel') }),
        Dialog.warnButton({ label: trans.__('Discard') })
      ]
    });
    if (result.button.accept) {
      try {
        await model.resetToCommit();
        return Promise.resolve(true);
      } catch (reason) {
        showErrorMessage(
          this.props.trans.__('Discard all changes failed.'),
          reason
        );
        return Promise.reject(reason);
      }
    } else {
      return Promise.reject('The user refused to discard the changes.');
    }
  };
```
